const raw = $('🎯 Agent 4: SEO & Monetization').item.json.message?.content || '';
let seo;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/s);
  seo = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  // Fallback: use humanized content directly
  seo = {
    optimized_content: $('🫂 Agent 3: Humanizer').item.json.message?.content || '',
    meta_title: $('✅ Parse & Validate Topic').item.json.topic,
    meta_description: 'A comprehensive how-to guide. Read the full article for step-by-step instructions.',
    focus_keyword: $('✅ Parse & Validate Topic').item.json.primary_keyword,
    slug: $('✅ Parse & Validate Topic').item.json.primary_keyword?.replace(/\s+/g, '-').toLowerCase(),
    tags: $('✅ Parse & Validate Topic').item.json.secondary_keywords || [],
    categories: ['How-To'],
    affiliate_ctas_added: 0,
    parse_error: e.message
  };
}

const content = seo.optimized_content || '';
const wordCount = content.replace(/<[^>]*>/g,' ').split(/\s+/).filter(Boolean).length;
const excerpt = content.replace(/<[^>]*>/g,' ').substring(0, 200).trim() + '...';

return [{ json: {
  title: seo.meta_title || $('✅ Parse & Validate Topic').item.json.topic,
  content,
  word_count: wordCount,
  excerpt,
  slug: seo.slug || seo.meta_title?.replace(/\s+/g,'-').toLowerCase(),
  focus_keyword: seo.focus_keyword,
  meta_description: seo.meta_description,
  tags: seo.tags || [],
  categories: seo.categories || ['How-To'],
  affiliate_ctas: seo.affiliate_ctas_added || 0,
  assembled_at: new Date().toISOString()
}}];

