const topic = $('✅ Parse & Validate Topic').item.json;
const keyword = topic.primary_keyword || topic.topic || 'productivity';
const queries = [
  keyword,
  keyword.split(' ').slice(0,2).join(' '),
  topic.secondary_keywords?.[0] || 'business success'
];
return [{ json: { queries, primary_query: queries[0] }}];

let imageUrl = null;
let imageAlt = $('✅ Parse & Validate Topic').item.json.primary_keyword || 'article image';

// Try Pexels first
try {
  const pexels = $('📸 Search Pexels').item.json;
  if (pexels.photos && pexels.photos.length > 0) {
    imageUrl = pexels.photos[0].src.large || pexels.photos[0].src.original;
  }
} catch(e) {}

// Fallback to Pixabay
if (!imageUrl) {
  try {
    const pixabay = $('📸 Search Pixabay (Fallback)').item.json;
    if (pixabay.hits && pixabay.hits.length > 0) {
      imageUrl = pixabay.hits[0].largeImageURL || pixabay.hits[0].webformatURL;
    }
  } catch(e) {}
}

const needsAI = !imageUrl;
return [{ json: { image_url: imageUrl, image_alt: imageAlt, needs_ai_image: needsAI }}];

const mediaResponse = $input.first().json;
// WordPress returns the media object with id field
const mediaId = mediaResponse.id || null;
const mediaUrl = mediaResponse.source_url || mediaResponse.guid?.rendered || '';
const imageAlt = $('🔀 Select Best Image').item.json.image_alt || '';

return [{ json: { media_id: mediaId, media_url: mediaUrl, image_alt: imageAlt }}];

